import React from 'react';
import Header from '../components/header/header';
import Footer from '../components/Footer/Footer';
import { ResolvedContentProvider } from '../ppm/util/ResolvedContentContext';
import { STATIC_VIDEOS } from '../contexts/db/videos';
import { Link } from 'gatsby';
import { useCMS } from '../contexts/CMSContext';

interface VideoDetailProps {
  pageContext: {
    item?: {
      id: string;
      title: string;
      description?: string;
      videoId: string;
      category?: string;
      date?: string;
      slug?: string;
    };
  };
  location?: any;
}

const VideoDetailInner: React.FC<VideoDetailProps> = ({ pageContext, location }) => {
  const { displayData } = useCMS();
  
  // --- RESTORED ORIGINAL LOGIC (DO NOT TOUCH) ---
  let item = pageContext?.item;
  if (!item) {
    const currentPath = location?.pathname;
    const slugOrId = currentPath?.split('/').filter(Boolean).pop();
    if (slugOrId) {
      const foundStatic = STATIC_VIDEOS.find((v: any) => 
        v.slug === slugOrId || 
        String(v.id) === String(slugOrId) || 
        `video-${v.id}` === slugOrId
      );
      if (foundStatic) {
        item = {
          id: String(foundStatic.id),
          title: String(foundStatic.title),
          videoId: foundStatic.videoId,
          description: foundStatic.description,
          category: foundStatic.category,
          date: foundStatic.date,
          slug: (foundStatic as any).slug || String(foundStatic.id)
        };
      } else {
        const homeSupport = displayData.pages.home.supportContent;
        const foundCMS = homeSupport.columns.flatMap(c => c.items).find(i => i.slug === slugOrId || i.id === slugOrId);
        if (foundCMS) {
          item = {
            id: foundCMS.id,
            title: foundCMS.title,
            videoId: foundCMS.videoId || '',
            description: '',
            category: 'Video',
            slug: foundCMS.slug || foundCMS.id
          };
        }
      }
    }
  }

  if (!item) {
    return (
      <div className="video-detail-page">
        <Header showHero={false} />
        <div className="error-container">
           <h2 style={{ fontFamily: 'var(--font-serif)' }}>Nội dung không tìm thấy</h2>
           <Link to="/videos" className="back-btn">Quay lại danh sách Video</Link>
        </div>
        <Footer />
      </div>
    );
  }

  const currentIndex = STATIC_VIDEOS.findIndex((v: any) => String(v.id) === String(item!.id));
  
  let nextParts: any[] = [];
  if (currentIndex !== -1) {
    nextParts = STATIC_VIDEOS.slice(currentIndex + 1, currentIndex + 9);
    if (nextParts.length < 5) {
      const additional = STATIC_VIDEOS
        .filter((v: any) => String(v.id) !== String(item!.id) && !nextParts.some(np => np.id === v.id))
        .slice(0, 5 - nextParts.length);
      nextParts = [...nextParts, ...additional] as any[];
    }
  } else {
    nextParts = STATIC_VIDEOS.slice(0, 8) as any[];
  }

  const relatedVideos = STATIC_VIDEOS
    .filter((v: any) => v.category === item!.category && String(v.id) !== String(item!.id))
    .slice(0, 4);

  const prevVideo = currentIndex > 0 ? (STATIC_VIDEOS[currentIndex - 1] as any) : null;
  const nextVideo = currentIndex < STATIC_VIDEOS.length - 1 ? (STATIC_VIDEOS[currentIndex + 1] as any) : null;
  // --- END RESTORED LOGIC ---

  return (
    <div className="video-detail-page">
      <Header showHero={false} />
      
      <main className="theater-main" >
        {/* TOP: CINEMA SECTION (Side-by-Side Video & Next List) */}
        <section className="cinema-wrapper" >
          
          <div className="video-column" style={{ marginTop : -30 }}>
              <div className="description-col">
            {item.description && <div className="video-description">{item.description}</div>}
            
            <div className="nav-navigation" style={{ marginBottom : 10 }}>
              {prevVideo && (
                <Link to={prevVideo.slug ? `/video/${prevVideo.slug}` : `/video-${prevVideo.id}`} className="nav-btn prev">
                  <span className="dir">TRƯỚC</span>
                  <span className="tit">{prevVideo.title}</span>
                </Link>
              )}
              {nextVideo && (
                <Link to={nextVideo.slug ? `/video/${nextVideo.slug}` : `/video/video-${nextVideo.id}`} className="nav-btn next">
                  <span className="dir">TIẾP THEO</span>
                  <span className="tit">{nextVideo.title}</span>
                </Link>
              )}
            </div>
          </div>
            <div className="player-container">
              <iframe
                src={`https://www.youtube.com/embed/${item.videoId}?modestbranding=1&rel=0`}
                title={item.title}
                allowFullScreen
              />
            </div>
            
            <div className="main-meta">
              <span className="cat-tag">{item.category}</span>
              <h1 className="main-title">{item.title}</h1>
              {item.date && <span className="date-tag">{item.date}</span>}
              <div className="gold-accent-line" />
            </div>
          </div>

          <aside className="next-up-aside">
            <div className="aside-header">
              <h3>TIẾP THEO TRONG LOẠT</h3>
            </div>
            <div className="aside-scroll-list">
              {nextParts.map(v => (
                <Link key={v.id} to={v.slug ? `/video/${v.slug}` : `/video/video-${v.id}`} className="aside-item">
                  <div className="aside-thumb">
                    <img src={`https://img.youtube.com/vi/${v.videoId}/mqdefault.jpg`} alt={v.title} />
                  </div>
                  <div className="aside-text">
                    <h4>{v.title}</h4>
                    <span>{v.date}</span>
                  </div>
                </Link>
              ))}
            </div>
          </aside>
        </section>

        {/* MIDDLE: DESCRIPTION & NAV */}
        <section className="details-layout">
        

          {/* BOTTOM: HORIZONTAL RELATED GRID */}
          <div className="related-row">
            <div className="row-header">
              <h3>VIDEOS CÙNG CHỦ ĐỀ</h3>
              <div className="gold-accent-line" />
            </div>
            <div className="related-grid-track">
              {relatedVideos.map(v => (
                <Link key={v.id} to={v.slug ? `/video/${v.slug}` : `/video/${v.id}`} className="rel-card">
                  <div className="rel-thumb">
                    <img src={`https://img.youtube.com/vi/${v.videoId}/mqdefault.jpg`} alt={v.title} />
                  </div>
                  <h4>{v.title}</h4>
                </Link>
              ))}
            </div>
          </div>
        </section>
      </main>

      <Footer />

      <style dangerouslySetInnerHTML={{ __html: `
        .video-detail-page { background: #fdfcf9; padding-top: 100px; color: #1a2a24; }
        .theater-main { max-width: 1400px; margin: 0 auto; padding: 20px; }

        /* THEATER SECTION */
        .cinema-wrapper { 
          display: grid; 
          grid-template-columns: 1fr 380px; 
          gap: 20px; 
          margin-bottom: 40px;
          align-items: start;
        }

        .player-container { 
          background: #000; 
          border-radius: 8px; 
          overflow: hidden; 
          aspect-ratio: 16/9; 
          max-height: 516px; /* Prevents pixelation/gigantic size */
          box-shadow: 0 10px 30px rgba(0,0,0,0.1);
        }
        .player-container iframe { width: 100%; height: 100%; border: none; }

        .main-meta { padding: 30px 0; }
        .cat-tag { color: var(--color-gold); font-weight: 700; font-size: 13px; text-transform: uppercase; letter-spacing: 1px; }
        .main-title { font-family: var(--font-serif); font-size: 2.5rem; margin: 10px 0; color: #1a2a24; line-height: 1.1; }
        .date-tag { color: #888; font-size: 14px; }
        .gold-accent-line { width: 80px; height: 4px; background: var(--color-gold); margin-top: 20px; }

        /* SIDEBAR (NEXT UP) */
        .next-up-aside { background: #fff; border: 1px solid #eee; border-radius: 8px; height: 600px; display: flex; flex-direction: column; }
        .aside-header { padding: 20px; border-bottom: 1px solid #f5f5f5; }
        .aside-header h3 { font-family: var(--font-serif); font-size: 1.1rem; margin: 0; color: var(--color-gold); }
        .aside-scroll-list { flex: 1; overflow-y: auto; padding: 15px; }
        .aside-item { display: grid; grid-template-columns: 100px 1fr; gap: 15px; text-decoration: none; margin-bottom: 20px; transition: opacity 0.2s; }
        .aside-item:hover { opacity: 0.7; }
        .aside-thumb img { width: 100%; border-radius: 4px; aspect-ratio: 16/9; object-fit: cover; }
        .aside-text h4 { font-size: 14px; margin: 0 0 5px; color: #333; line-height: 1.3; }
        .aside-text span { font-size: 12px; color: #999; }

        /* BOTTOM DETAILS */
        .details-layout { display: grid; grid-template-columns: 1fr; gap: 40px; }
        .video-description { font-size: 1.1rem; line-height: 1.8; color: #444; margin-bottom: 40px; max-width: 900px; }

        .nav-navigation { display: flex; gap: 20px; border-top: 0px solid #eee; padding-top: 30px; }
        .nav-btn { flex: 1; text-decoration: none; padding: 20px; border: 1px solid #eee; border-radius: 8px; transition: 0.3s; }
        .nav-btn:hover { border-color: var(--color-gold); background: #fff; transform: translateY(-3px); }
        .nav-btn.next { text-align: right; }
        .dir { font-size: 11px; font-weight: 700; color: var(--color-gold); display: block; margin-bottom: 5px; }
        .tit { font-size: 15px; font-weight: 600; color: #1a2a24; }

        /* RELATED ROW */
        .related-row { margin-top: 60px; }
        .related-grid-track { display: grid; grid-template-columns: repeat(4, 1fr); gap: 20px; padding-top: 20px; }
        .rel-card { text-decoration: none; }
        .rel-thumb img { width: 100%; border-radius: 8px; margin-bottom: 12px; transition: 0.3s; }
        .rel-card:hover .rel-thumb img { transform: scale(1.03); }
        .rel-card h4 { font-size: 14px; color: #333; margin: 0; line-height: 1.4; }

        .error-container { height: 60vh; display: flex; flex-direction: column; align-items: center; justify-content: center; }
        .back-btn { background: #9b2c21; color: #fff; padding: 12px 30px; border-radius: 30px; text-decoration: none; font-weight: 700; margin-top: 20px; }

        /* RESPONSIVENESS */
        @media (max-width: 1024px) {
          .cinema-wrapper { grid-template-columns: 1fr; }
          .next-up-aside { height: 400px; }
          .related-grid-track { grid-template-columns: 1fr 1fr; }
          .main-title { font-size: 2rem; }
        }
        @media (max-width: 600px) {
          .nav-navigation { flex-direction: column; }
          .related-grid-track { grid-template-columns: 1fr; }
        }
      `}} />
    </div>
  );
};

const VideoDetail = (props: VideoDetailProps) => (
  <ResolvedContentProvider>
    <VideoDetailInner {...props} />
  </ResolvedContentProvider>
);

export default VideoDetail;